import datetime

def hydrate_time(nanoseconds, tz=None):
    secs = nanoseconds / 1e9
    dt = datetime.datetime.utcfromtimestamp(secs)
    if tz is not None:
        dt = dt.replace(tzinfo=datetime.timezone.utc).astimezone(tz)
    return dt.time()

def keys(self):
    """
    Return the keys of the record.

    :return: list of key names
    """
    return list(self._data.keys())

def unit_of_work(metadata=None, timeout=None):
    def decorator(func):
        def wrapper(session, *args, **kwargs):
            transaction_config = {}
            if metadata is not None:
                transaction_config["metadata"] = metadata
            if timeout is not None:
                transaction_config["timeout"] = timeout
            return session.write_transaction(func, *args, **kwargs, transaction_config=transaction_config)
        return wrapper
    return decorator

def index(self, key):
    for i, item in enumerate(self._data):
        if item == key:
            return i
    return -1

def values(self, *keys):
    if not keys:
        return list(self.values())
    result = []
    vals = list(self.values())
    for k in keys:
        if isinstance(k, int):
            try:
                result.append(vals[k])
            except IndexError:
                pass
        else:
            if k in self:
                result.append(self[k])
    return result

def data(self, *keys):
    """
    Return the keys and values of this record as a dictionary,
    optionally including only certain values by index or key. Keys
    provided in the items that are not in the record will be
    inserted with a value of :const:`None`; indexes provided
    that are out of bounds will trigger an :exc:`IndexError`.

    :param keys: indexes or keys of the items to include; if none
              are provided, all values will be included
    :return: dictionary of values, keyed by field name
    :raises: :exc:`IndexError` if an out-of-bounds index is specified
    """
    if not keys:
        return dict(zip(self._keys, self._values))
    result = {}
    for k in keys:
        if isinstance(k, int):
            if k < 0 or k >= len(self._values):
                raise IndexError("Index out of range")
            key_name = self._keys[k]
            result[key_name] = self._values[k]
        elif isinstance(k, str):
            key_name = k
            if k in self._keys:
                idx = self._keys.index(k)
                result[key_name] = self._values[idx]
            else:
                result[key_name] = None
        else:
            raise TypeError("Keys must be int or str")
    return result

