def normalize_cmd(cmd: tuple[str, ...]) -> tuple[str, ...]:
    """
    Fixes for the following issues on windows
    - https://bugs.python.org/issue8557
    - windows does not parse shebangs

    This function also makes deep-path shebangs work just fine
    """
    import os, sys
    if not cmd:
        return cmd
    first = cmd[0]
    if os.path.isfile(first):
        try:
            with open(first, 'r', encoding='utf-8') as f:
                first_line = f.readline()
        except Exception:
            first_line = ''
        if first_line.startswith('#!'):
            parts = first_line[2:].strip().split()
            if parts:
                interpreter = parts[0]
                if 'env' in interpreter:
                    interpreter = sys.executable
                elif not os.path.isabs(interpreter):
                    interpreter = os.path.join(os.path.dirname(first), interpreter)
                return (interpreter, first) + cmd[1:]
    if first.lower().endswith(('.py', '.pyw')):
        return (sys.executable, first) + cmd[1:]
    return cmd

def cached(cache, key=hashkey, lock=None):
    def decorator(func):
        def wrapper(*args, **kwargs):
            k = key(args, **kwargs)
            if lock:
                with lock:
                    if k in cache:
                        return cache[k]
            else:
                if k in cache:
                    return cache[k]
            result = func(*args, **kwargs)
            if lock:
                with lock:
                    cache[k] = result
            else:
                cache[k] = result
            return result
        return wrapper
    return decorator

def ttl_cache(maxsize=128, ttl=600, timer=time.monotonic, typed=False):
    import functools
    from collections import OrderedDict

    def decorator(func):
        cache = OrderedDict()
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            if typed:
                key = (args, tuple(sorted(kwargs.items())), tuple(type(arg) for arg in args), tuple(type(v) for v in kwargs.values()))
            else:
                key = (args, tuple(sorted(kwargs.items())))
            now = timer()
            if key in cache:
                value, timestamp = cache[key]
                if now - timestamp < ttl:
                    cache.move_to_end(key)
                    return value
                else:
                    del cache[key]
            value = func(*args, **kwargs)
            cache[key] = (value, now)
            if len(cache) > maxsize:
                cache.popitem(last=False)
            return value
        return wrapper
    return decorator

def mru_cache(maxsize=128, typed=False):
    import functools
    def decorating_function(user_function):
        if maxsize <= 0:
            return user_function
        cache = {}
        usage = []  # most recent key at index 0
        def make_key(args, kwargs):
            if typed:
                key = args + tuple((k, type(v)) for k, v in sorted(kwargs.items()))
            else:
                key = args + tuple(sorted(kwargs.items()))
            return key
        @functools.wraps(user_function)
        def wrapper(*args, **kwargs):
            key = make_key(args, kwargs)
            if key in cache:
                usage.remove(key)
                usage.insert(0, key)
                return cache[key]
            result = user_function(*args, **kwargs)
            if len(cache) >= maxsize:
                evict_key = usage.pop(0)
                del cache[evict_key]
            cache[key] = result
            usage.insert(0, key)
            return result
        return wrapper
    return decorating_function

def lru_cache(maxsize=128, typed=False):
    def decorating(func):
        cache = {}
        order = []
        def wrapper(*args, **kwargs):
            key = args
            if typed:
                key += tuple(type(v) for v in args)
            for k, v in kwargs.items():
                key += (k, v)
                if typed:
                    key += (type(v),)
            if key in cache:
                order.remove(key)
                order.append(key)
                return cache[key]
            result = func(*args, **kwargs)
            cache[key] = result
            order.append(key)
            if len(cache) > maxsize:
                oldest = order.pop(0)
                del cache[oldest]
            return result
        return wrapper
    return decorating

def lfu_cache(maxsize=128, typed=False):
    def decorating_function(user_function):
        if maxsize <= 0:
            return user_function
        cache = {}
        freq_table = {}
        minfreq = 0

        def get_key(args, kwargs):
            if typed:
                key = args + tuple((k, type(v), v) for k, v in sorted(kwargs.items()))
            else:
                key = args + tuple(kwargs.items())
            return key

        def wrapper(*args, **kwargs):
            nonlocal minfreq
            key = get_key(args, kwargs)
            if key in cache:
                value, freq = cache[key]
                cache[key] = (value, freq + 1)
                freq_table[freq].pop(key, None)
                if not freq_table[freq]:
                    del freq_table[freq]
                    if minfreq == freq:
                        minfreq += 1
                freq_table.setdefault(freq + 1, {})
                freq_table[freq + 1][key] = None
                return value
            value = user_function(*args, **kwargs)
            if len(cache) >= maxsize:
                evict_key = next(iter(freq_table[minfreq]))
                freq_table[minfreq].pop(evict_key, None)
                if not freq_table[minfreq]:
                    del freq_table[minfreq]
                cache.pop(evict_key, None)
            cache[key] = (value, 1)
            freq_table.setdefault(1, {})
            freq_table[1][key] = None
            minfreq = 1
            return value
        return wrapper
    return decorating_function

def popitem(self):
    if not self:
        raise KeyError('popitem(): dictionary is empty')
    key, value = next(iter(self.items()))
    del self[key]
    return key, value

