def cachedmethod(cache, key=hashkey, lock=None):
    def decorator(func):
        def wrapper(self, *args, **kwargs):
            if callable(key):
                cache_key = key(self, *args, **kwargs)
            else:
                cache_key = (func.__qualname__, self, *args, **kwargs)
            if lock:
                with lock:
                    if cache_key in cache:
                        return cache[cache_key]
                    result = func(self, *args, **kwargs)
                    cache[cache_key] = result
                    return result
            else:
                if cache_key in cache:
                    return cache[cache_key]
                result = func(self, *args, **kwargs)
                cache[cache_key] = result
                return result
        return wrapper
    return decorator

def extostr(cls, e, max_level=30, max_path_level=5):
    import traceback, os
    tb = e.__traceback__
    if not tb:
        return f"{type(e).__name__}: {e}"
    frames = traceback.extract_tb(tb)[:max_level]
    parts = []
    parts.append("Traceback (most recent call last):")
    for frame in frames:
        path = frame.filename
        parts = path.split(os.sep)
        if len(parts) > max_path_level:
            path = os.sep.join(parts[-max_path_level:])
        parts.append(f'  File "{path}", line {frame.lineno}, in {frame.name}')
        if frame.line:
            parts.append(f"    {frame.line.strip()}")
    parts.append(f"{type(e).__name__}: {e}")
    return "\n".join(parts)

