def _legacy_mergeOrderings(orderings):
    def merge_two(a, b):
        i = j = None
        for idx_a, val_a in enumerate(a):
            for idx_b, val_b in enumerate(b):
                if val_a == val_b:
                    i, j = idx_a, idx_b
                    break
            if i is not None:
                break
        if i is None:
            return a + b
        if a[i:] != b[j:]:
            raise ValueError("Suffixes do not match")
        return a[:i] + b[:j] + a[i:]
    if not orderings:
        return []
    result = orderings[0]
    for ordering in orderings[1:]:
        result = merge_two(result, ordering)
    return result

