def difference(d1, d2, level=-1):
    import copy
    result = {}
    for key, val in d1.items():
        if key not in d2:
            result[key] = copy.deepcopy(val)
        else:
            val2 = d2[key]
            if isinstance(val, dict) and isinstance(val2, dict):
                if level == 0:
                    result[key] = copy.deepcopy(val)
                else:
                    new_level = level-1 if level > 0 else -1
                    sub_diff = difference(val, val2, new_level)
                    if sub_diff:
                        result[key] = sub_diff
            else:
                if val != val2:
                    result[key] = copy.deepcopy(val)
    return result

def fill(self, coord, weight=1):
    """
    Fill histogram at *coord* with the given *weight*.

    Coordinates outside the histogram edges are ignored.
    """
    if isinstance(coord, (list, tuple, np.ndarray)):
        indices = []
        for d, edge in enumerate(self.edges):
            c = coord[d]
            if c < edge[0] or c >= edge[-1]:
                return
            idx = np.searchsorted(edge, c, side='right') - 1
            indices.append(idx)
        self.counts[tuple(indices)] += weight
    else:
        edge = self.edges[0]
        if coord < edge[0] or coord >= edge[-1]:
            return
        idx = np.searchsorted(edge, coord, side='right') - 1
        self.counts[idx] += weight

def _validate_labels(labels):
    import re
    KEY_REGEX = re.compile(r'^[A-Za-z0-9_]+$')
    errors = []
    for key, value in labels.items():
        if not isinstance(key, (str, bytes)):
            errors.append({str(key): 'expected string or bytes-like object'})
        elif not KEY_REGEX.match(key):
            errors.append({key: f"Label key '{key}' does not match the regex [...]"})
        # validate value
        if isinstance(value, (str, bytes)):
            pass
        elif isinstance(value, (list, tuple)):
            for v in value:
                if not isinstance(v, (str, bytes)):
                    errors.append({str(v): 'expected string or bytes-like object'})
        else:
            errors.append({str(value): 'expected string or bytes-like object'})
    if errors:
        raise ValidationError(errors)

