def generate_default_observer_schema_dict(manifest_dict, first_level=False):
    """
    Together with :func:``generate_default_observer_schema_list``, this function is
    called recursively to generate part of a default ``observer_schema`` from part of a
    Kubernetes resource, defined respectively by ``manifest_dict`` or ``manifest_list``.

    Args:
        manifest_dict (dict): Partial Kubernetes resources
        first_level (bool, optional): If True, indicates that the dictionary represents
            the whole observer schema of a Kubernetes resource

    Returns:
        dict: Generated partial observer_schema

    This function creates a new dictionary from ``manifest_dict`` and replaces all
    non-list and non-dict values by ``None``.

    In case of ``first_level`` dictionary (i.e. complete ``observer_schema`` for a
    resource), the values of the identifying fields are copied from the manifest file.
    """
    result = {}
    for key, value in manifest_dict.items():
        if isinstance(value, dict):
            result[key] = generate_default_observer_schema_dict(value, first_level=False)
        elif isinstance(value, list):
            result[key] = value
        else:
            result[key] = None
    if first_level:
        for identifying_key in ("apiVersion", "kind"):
            if identifying_key in result:
                result[identifying_key] = manifest_dict.get(identifying_key)
        if "metadata" in result and isinstance(result["metadata"], dict):
            metadata = manifest_dict.get("metadata", {})
            for meta_key in ("name", "namespace"):
                if meta_key in metadata:
                    result["metadata"][meta_key] = metadata[meta_key]
    return result

def update_last_applied_manifest_list_from_resp(last_applied_manifest, observer_schema, response):
    for schema_item in observer_schema:
        match = None
        for resp_item in response:
            key = schema_item.get('key')
            if key and resp_item.get(key) == schema_item.get(key):
                match = resp_item
                break
        if match:
            if 'schema' in schema_item and isinstance(match, dict):
                update_last_applied_manifest_dict_from_resp(last_applied_manifest, schema_item['schema'], match)
            else:
                if match not in last_applied_manifest:
                    last_applied_manifest.append(match)
    return last_applied_manifest

def update_last_applied_manifest_dict_from_resp(
    last_applied_manifest, observer_schema, response
):
    """
    Together with :func:``update_last_applied_manifest_list_from_resp``, this
    function is called recursively to update a partial ``last_applied_manifest``
    from a partial Kubernetes response

    Args:
        last_applied_manifest (dict): partial ``last_applied_manifest`` being
            updated
        observer_schema (dict): partial ``observer_schema``
        response (dict): partial response from the Kubernetes API.

    Raises:
        KeyError: If the observed field is not present in the Kubernetes response

    This function go through all observed fields, and initialized their value in
    last_applied_manifest if they are not yet present
    """
    for key, schema in observer_schema.items():
        if key not in response:
            raise KeyError(key)
        value = response[key]
        if isinstance(schema, dict):
            if key not in last_applied_manifest or not isinstance(last_applied_manifest[key], dict):
                last_applied_manifest[key] = {}
            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[key], schema, value
            )
        elif isinstance(schema, list):
            if key not in last_applied_manifest or not isinstance(last_applied_manifest[key], list):
                last_applied_manifest[key] = []
            update_last_applied_manifest_list_from_resp(
                last_applied_manifest[key], schema, value
            )
        else:
            if key not in last_applied_manifest:
                last_applied_manifest[key] = value
    return last_applied_manifest

def generate_default_observer_schema(app):
    if not hasattr(app.spec, 'observer_schema') or app.spec.observer_schema is None:
        app.spec.observer_schema = {}
    for resource in app.spec.manifest:
        kind = resource.get('kind')
        name = resource.get('metadata', {}).get('name')
        if kind and name:
            key = f"{kind}/{name}"
            if key not in app.spec.observer_schema:
                app.spec.observer_schema[key] = {}
    return app.spec.observer_schema

