def validate_as_prior_version(self, prior):
    if not isinstance(prior, InventoryValidator):
        raise TypeError("prior must be an InventoryValidator")
    if prior.version >= self.version:
        raise ValueError("prior version must be less than current version")
    if prior.inventory_id != self.inventory_id:
        raise ValueError("prior inventory ID must match current inventory ID")
    if prior.timestamp >= self.timestamp:
        raise ValueError("prior timestamp must be earlier than current timestamp")
    return True

def get_logical_path_map(inventory, version):
    result = {}
    current = inventory.get(version, {})
    for logical_path, content_file in current.items():
        result[logical_path] = {content_file}
    for later_version, mapping in inventory.items():
        if later_version > version:
            for logical_path, content_file in mapping.items():
                if logical_path in result:
                    result[logical_path].add(content_file)
    return result

def validate_fixity(self, fixity, manifest_files):
    if not isinstance(fixity, list):
        raise TypeError("fixity must be a list")
    manifest_set = set(manifest_files)
    seen = set()
    for entry in fixity:
        if not isinstance(entry, dict):
            raise TypeError("each fixity entry must be a dict")
        filename = entry.get('filename')
        if filename is None:
            raise ValueError("fixity entry missing 'filename'")
        if filename not in manifest_set:
