def deep_merge_nodes(nodes):
    def merge_nodes(node_a, node_b):
        if isinstance(node_a, ruamel.yaml.nodes.MappingNode) and isinstance(node_b, ruamel.yaml.nodes.MappingNode):
            merged = {}
            for k, v in node_a.value:
                merged[k.value] = (k, v)
            for k, v in node_b.value:
                if k.value in merged:
                    merged[k.value] = (k, merge_nodes(merged[k.value][1], v))
                else:
                    merged[k.value] = (k, v)
            return ruamel.yaml.nodes.MappingNode(node_a.tag, list(merged.values()))
        return node_b
    result = {}
    for key_node, value_node in nodes:
        key = key_node.value
        if key in result:
            result[key] = (key_node, merge_nodes(result[key][1], value_node))
        else:
            result[key] = (key_node, value_node)
    return list(result.values())

