def split(s, platform='this'):
    """
    Multi-platform variant of shlex.split() for command-line splitting.
    For use with subprocess, for argv injection etc. Using fast REGEX.
    platform: 'this' = auto from current platform;
          1 = POSIX;
          0 = Windows/CMD
          (other values reserved)
    """
    if platform == 'this':
        if os.name == 'nt' or sys.platform.startswith('win'):
            platform = 0
        else:
            platform = 1
    if platform == 1:
        return shlex.split(s, posix=True)
    elif platform == 0:
        return shlex.split(s, posix=False)
    else:
        raise ValueError('Unsupported platform value')

def parse_frequency(frequency):
    import re, datetime
    if frequency is None or str(frequency).strip().lower() == "always":
        return None
    m = re.match(r'^\s*(\d+(?:\.\d+)?)\s*([a-zA-Z]+)\s*$', frequency)
    if not m:
        raise ValueError(f"Unable to parse frequency: {frequency}")
    number_str, unit = m.groups()
    number = float(number_str)
    unit = unit.lower()
    if unit.endswith('s'):
        unit = unit[:-1]
    if unit in ('day', 'days'):
        return datetime.timedelta(days=number)
    elif unit in ('week', 'weeks'):
        return datetime.timedelta(weeks=number)
    elif unit in ('hour', 'hours'):
        return datetime.timedelta(hours=number)
    elif unit in ('minute', 'minutes'):
        return datetime.timedelta(minutes=number)
    elif unit in ('second', 'seconds'):
        return datetime.timedelta(seconds=number)
    else:
        raise ValueError(f"Unsupported unit in frequency: {unit}")

