        raise TypeError("Scale must be numeric")
    if not hasattr(self, "_scale") or self._scale == 0:
        raise LenaValueError("Cannot rescale unknown or zero scale")
    factor = other / self._scale
    last_field = self.fields[-1]
    self.data[last_field] = self.data[last_field] * factor
