    points = []
    for i, content in enumerate(contents):
        values = make_value(content) if make_value else content
        if get_coordinate == "left":
            x = edges[i]
        elif get_coordinate == "right":
            x = edges[i+1]
        else:
            x = (edges[i] + edges[i+1]) / 2
        if isinstance(values, (tuple, list)):
            point = {field: val for field, val in zip(field_names, values)}
        else:
            point = {field_names[0]: x, field_names[1]: values}
        points.append(point)
    graph = type('Graph', (), {})()
    graph.points = points
    graph.scale = hist.scale if scale is True else scale
    return graph

def verifyObject(iface, candidate, tentative=False):
    if not tentative:
        if not iface.providedBy(candidate):
            raise zope.interface.Invalid(f"{candidate} does not provide {iface}")
    errors = []
    for name, interface_method in iface.getInterfaceMethods().items():
        if not hasattr(candidate, name):
            errors.append(f"{candidate} is missing method {name}")
            continue
        attr = getattr(candidate, name)
        if not callable(attr):
            errors.append(f"{candidate}.{name} is not callable")
            continue
        try:
            interface_sig = interface_method.signature
            cand_sig = inspect.signature(attr)
            if interface_sig != cand_sig:
                errors.append(f"Signature mismatch for {candidate}.{name}: expected {interface_sig}, got {cand_sig}")
        except Exception as e:
            errors.append(f"Error checking signature for {candidate}.{name}: {e}")
    for name, interface_attr in iface.getInterfaceAttributes().items():
        if not hasattr(candidate, name):
            errors.append(f"{candidate} is missing attribute {name}")
    if errors:
        if len(errors) == 1:
            raise zope.interface.Invalid(errors[0])
        else:
            raise zope.interface.Invalid("\n".join(errors))
    return True

def verifyClass(iface, candidate, tentative=False):
    """
    Verify that the *candidate* might correctly provide *iface*.
    """
    for name, attr in iface.__dict__.items():
        if name.startswith('__') and name.endswith('__'):
            continue
        if not hasattr(candidate, name):
            return False
        cand_attr = getattr(candidate, name)
        if callable(attr):
            if not callable(cand_attr):
                return False
    return True

def determineMetaclass(bases, explicit_mc=None):
    metaclasses = [type(b) for b in bases]
    if explicit_mc is not None:
        metaclass = explicit_mc
    else:
        metaclass = metaclasses[0]
        for mc in metaclasses[1:]:
            if issubclass(mc, metaclass):
                metaclass = mc
    for mc in metaclasses:
        if not issubclass(metaclass, mc):
            raise TypeError("Metaclass conflict")
    return metaclass

def pop(self, key, default=__marker):
    if key in self:
        value = self[key]
        del self[key]
        return value
    if default is __marker:
        raise KeyError(key)
    return default

def popitem(self):
    if not self:
        raise KeyError('popitem(): dictionary is empty')
    min_key = None
    min_freq = float('inf')
    for key in self:
        freq = self._freq.get(key, 0)
        if freq < min_freq:
            min_freq = freq
            min_key = key
    value = super().pop(min_key)
    return (min_key, value)

