def parse(self, timestr, default=None, ignoretz=False, tzinfos=None, **kwargs):
    if isinstance(timestr, datetime.datetime):
        if default is None:
            return timestr
        return default.replace(
            year=timestr.year,
            month=timestr.month,
            day=timestr.day,
            hour=timestr.hour,
            minute=timestr.minute,
            second=timestr.second,
            microsecond=timestr.microsecond,
            tzinfo=timestr.tzinfo
        )
    parse_kwargs = kwargs.copy()
    if tzinfos is not None:
        parse_kwargs['tzinfos'] = tzinfos
    if ignoretz:
        parse_kwargs['ignoretz'] = True
    return dateutil.parser.parse(timestr, **parse_kwargs)

