def find_tags(text: str, replacer: callable = None) -> Tuple[Set, str]:
    import re
    from typing import Set, Tuple
    code_block_delim = r'```'
    parts = re.split(code_block_delim, text)
    tags = set()
    for i, part in enumerate(parts):
        if i % 2 == 0:
            found = re.findall(r'#\w+', part)
            tags.update(found)
            if replacer:
                for tag in found:
                    part = part.replace(tag, replacer(tag))
                parts[i] = part
    result_text = code_block_delim.join(parts)
    return tags, result_text

def process_text_links(text):
