def parse_diaspora_webfinger(document: str) -> Dict:
    import json, xml.etree.ElementTree as ET
    document = document.strip()
    if document.startswith('{') or document.startswith('['):
        return json.loads(document)
    try:
        root = ET.fromstring(document)
        ns = {'xrd': 'http://docs.oasis-open.org/ns/xri/xrd-1.0'}
        subject = root.find('xrd:Subject', ns)
        subject_text = subject.text if subject is not None else None
        links = []
        for link in root.findall('xrd:Link', ns):
            rel = link.attrib.get('rel')
            href = link.attrib.get('href')
            links.append({'rel': rel, 'href': href})
        return {'subject': subject_text, 'links': links}
    except ET.ParseError:
        return {}

