def dict_insert(dic, val, key, *keys):
    all_keys = [key] + list(keys)
    current = dic
    for i, k in enumerate(all_keys):
        if i == len(all_keys) - 1:
            current[k] = val
        else:
            if k not in current or not isinstance(current[k], dict):
                current[k] = {}
            current = current[k]
    return dic

