def validate_min_max_args(self, args):
    """
    Check if value of arguments is between minimum and maximum values.

    :param args: The received arguments.
    """
    for key, value in args.items():
        min_val = self.min_args.get(key) if hasattr(self, 'min_args') else None
        max_val = self.max_args.get(key) if hasattr(self, 'max_args') else None
        if min_val is None or max_val is None:
            continue
        if not (min_val <= value <= max_val):
            raise ValueError(f"Argument {key}={value} is out of range [{min_val}, {max_val}]")
    return True

def get_nested_custom_and_control_args(self, args):
    control_args = {}
    nested_args = {}
    for arg in args:
        if isinstance(arg, dict):
            for k, v in arg.items():
                if k.startswith('control.') or k.startswith('control'):
                    key = k[len('control.') if k.startswith('control.') else 0:]
                    control_args[key] = v
                else:
                    nested_args[k] = v
        elif isinstance(arg, str) and '=' in arg:
            k, v = arg.split('=', 1)
            if k.startswith('control.') or k.startswith('control'):
                key = k[len('control.') if k.startswith('control.') else 0:]
                control_args[key] = v
            else:
                nested_args[k] = v
    return control_args, nested_args

def merge_extra_vars(vars_dict, extra_vars=None):
    if extra_vars is None:
        return vars_dict
    if isinstance(extra_vars, dict):
        vars_dict.update(extra_vars)
    elif isinstance(extra_vars, list):
        for item in extra_vars:
            if isinstance(item, dict):
                vars_dict.update(item)
            elif isinstance(item, tuple) and len(item) == 2:
                vars_dict[item[0]] = item[1]
    return vars_dict

def ansible_playbook(ir_workspace, ir_plugin, playbook_path, verbose=None,
                     extra_vars=None, ansible_args=None):
    import subprocess, shlex, json
    cmd = ['ansible-playbook']
    if verbose:
        cmd.extend(['-' + 'v' * verbose])
    if ansible_args:
        for k, v in ansible_args.items():
            if isinstance(v, bool):
                if v:
                    cmd.append(f'--{k}')
            else:
                cmd.append(f'--{k}={shlex.quote(str(v))}')
    cmd.append(playbook_path)
    if extra_vars:
        extra_str = json.dumps(extra_vars)
        cmd.append(f'--extra-vars={shlex.quote(extra_str)}')
    result = subprocess.run(cmd, capture_output=True, text=True)
    return result

def _convert_non_cli_args(self, parser_name, values_dict):
    for k, v in list(values_dict.items()):
        if isinstance(v, str):
            lowered = v.lower()
            if lowered == 'true':
                values_dict[k] = True
            elif lowered == 'false':
                values_dict[k] = False
            else:
                try:
                    if '.' in v:
                        values_dict[k] = float(v)
                    else:
                        values_dict[k] = int(v)
                except ValueError:
                    try:
                        values_dict[k] = eval(v)
                    except:
                        pass
    return values_dict

def get_plugin_spec_flatten_dict(plugin_dir):
    import os, json
    spec_path = os.path.join(plugin_dir, "plugin.json")
    if not os.path.isfile(spec_path):
        raise FileNotFoundError("plugin.json not found")
    with open(spec_path, "r", encoding="utf-8") as f:
        spec = json.load(f)
    def flatten(d, parent_key=""):
        items = {}
        for k, v in d.items():
            new_key = f"{parent_key}.{k}" if parent_key else k
            if isinstance(v, dict):
                items.update(flatten(v, new_key))
            else:
                items[new_key] = v
        return items
    return flatten(spec)

